pub fn process_swap(
    program_id: &Pubkey,
    amount_in: u64,
    minimum_amount_out: u64,
    accounts: &[AccountInfo],
) -> ProgramResult {
    let token_swap = SwapVersion::unpack(&swap_info.data.borrow())?;

    // FIRST: Transfer user's source tokens INTO the pool
    Self::token_transfer(
        swap_info.key, source_token_program_info.clone(),
        source_info.clone(), source_token_mint_info.clone(),
        swap_source_info.clone(), user_transfer_authority_info.clone(),
        token_swap.bump_seed(), source_transfer_amount, source_mint_decimals,
    )?;

    // THEN: Transfer pool's destination tokens OUT to user
    Self::token_transfer(
        swap_info.key, destination_token_program_info.clone(),
        swap_destination_info.clone(), destination_token_mint_info.clone(),
        destination_info.clone(), authority_info.clone(),
        token_swap.bump_seed(), destination_transfer_amount, destination_mint_decimals,
    )?;

    Ok(())
}
